def A344720(n):
    c, j = 0, 1
    while j <= n:
        k = n//j
        m = n//k
        c += k**2*(m-j+1&1 if j&1 else -(m-j+1&1))
        j = m+1
    return c # _Chai Wah Wu_, May 13 2026

